// Récupère TOUS les items venant du CSV
const allItems = $input.all();

let total_defects = allItems.length;
let total_repair_cost = 0;
let valid_repair_costs = 0;
let severity_counts = {};
let defect_type_counts = {};
let location_counts = {};
let inspection_counts = {};

allItems.forEach(item => {
  const row = item.json;

  // Calcul des coûts de réparation
  if (row.repair_cost != null && !isNaN(parseFloat(row.repair_cost))) {
    total_repair_cost += parseFloat(row.repair_cost);
    valid_repair_costs++;
  }

  // Distribution par sévérité
  const severity = String(row.severity || "unknown").trim();
  severity_counts[severity] = (severity_counts[severity] || 0) + 1;

  // Distribution par type de défaut
  const defectType = String(row.defect_type || "unknown").trim();
  defect_type_counts[defectType] = (defect_type_counts[defectType] || 0) + 1;

  // Distribution par localisation
  const location = String(row.defect_location || "unknown").trim();
  location_counts[location] = (location_counts[location] || 0) + 1;

  // Distribution par méthode d'inspection
  const inspection = String(row.inspection_method || "unknown").trim();
  inspection_counts[inspection] = (inspection_counts[inspection] || 0) + 1;
});

const avg_repair_cost = valid_repair_costs > 0 
  ? Math.round((total_repair_cost / valid_repair_costs) * 100) / 100 
  : 0;

return [{
  json: {
    kpis: {
      total_defects: total_defects,
      total_repair_cost: Math.round(total_repair_cost * 100) / 100,
      avg_repair_cost: avg_repair_cost,
      valid_repair_cost_count: valid_repair_costs,
      severity_distribution: severity_counts,
      most_common_severity: Object.keys(severity_counts).reduce((a, b) => severity_counts[a] > severity_counts[b] ? a : b),
      defect_type_distribution: defect_type_counts,
      defect_location_distribution: location_counts,
      inspection_method_distribution: inspection_counts
    },
    sample_data: allItems.slice(0, 10)   // 10 exemples pour l'IA
  }
}];

