// ════════════════════════════════════════════════════════════
//  AI PDCA Orchestrator — Code in JavaScript6 (nœud HTML)
//  Workflow : CSV → LLM CHECK → LLM ACT → LLM PLAN → HTML
// ════════════════════════════════════════════════════════════

const input = $input.first().json;

// ── 1. PARSING DÉFENSIF ──────────────────────────────────────
// Les LLM renvoient souvent des strings JSON avec \" échappés
function parseField(val) {
  if (!val) return null;
  if (typeof val === 'object') return val;
  if (typeof val !== 'string') return null;
  const s = val.trim();
  // Tentative 1 : JSON direct
  try { return JSON.parse(s); } catch (_) {}
  // Tentative 2 : nettoyage des échappements \" → "
  try {
    const c = s.replace(/\\"/g, '"').replace(/\\n\s*/g, ' ').replace(/\\\\/g, '\\');
    return JSON.parse(c);
  } catch (_) {}
  // Tentative 3 : fix indicateurs_de_succes avec syntaxe Set {} invalide
  try {
    const c = s
      .replace(/\\"/g, '"').replace(/\\n\s*/g, ' ')
      .replace(/"indicateurs_de_succes"\s*:\s*\{([^}]*)\}/g, (_, inner) => {
        const items = inner.match(/"([^"]+)"/g) || [];
        return `"indicateurs_de_succes": [${items.join(',')}]`;
      });
    return JSON.parse(c);
  } catch (_) {}
  return null;
}

function parseArray(val) {
  if (!val) return [];
  if (Array.isArray(val)) return val;
  const p = parseField(val);
  if (Array.isArray(p)) return p;
  if (p && typeof p === 'object') return [p];
  return [];
}

// ── 2. EXTRACTION DONNÉES ────────────────────────────────────
// Les KPIs arrivent sous input.kpis.sample_data OU directement input.kpis
const rawKpisRoot = input.kpis || input.kpi || {};
const rawKpisObj  = (typeof rawKpisRoot === 'object' && !Array.isArray(rawKpisRoot))
  ? rawKpisRoot : (parseField(rawKpisRoot) || {});

// Chercher sous sample_data ou directement à la racine
const kpis = rawKpisObj.sample_data || rawKpisObj;

// Distributions pour les graphiques
const severityDist   = kpis.severity_distribution   || {};
const defectTypeDist = kpis.defect_type_distribution || {};
const locationDist   = kpis.defect_location_distribution || {};
const methodDist     = kpis.inspection_method_distribution || {};

// CHECK, ACT, PLAN — multi-clés + fallback
const rawCheck = input.check_analyse || input.analyse || input.check || null;
const rawAct   = input.act_decisions || input.decisions || input.act || null;
const rawPlan  = input.plan_action   || input.plan     || null;

const check = parseField(rawCheck) || {};
const act   = parseArray(rawAct);
const plan  = parseField(rawPlan)  || {};

const doMsg = input.do_simulation || 'Plan simulé et mis en oeuvre automatiquement pour le prochain cycle PDCA.';

// ── 3. HELPERS ───────────────────────────────────────────────
const fmt    = v => (v !== undefined && v !== null) ? Number(v).toLocaleString('fr-FR', { minimumFractionDigits: 0, maximumFractionDigits: 2 }) : '-';
const fmtEur = v => v ? fmt(v) + ' EUR' : '-';
const safe   = v => (v !== undefined && v !== null && v !== '') ? v : '-';
const today  = new Date().toLocaleDateString('fr-FR', { year: 'numeric', month: 'long', day: 'numeric' });

// ── 4. RENDU DISTRIBUTIONS (mini bar chart HTML) ─────────────
function renderDistribution(distObj, colorClass) {
  if (!distObj || Object.keys(distObj).length === 0) return '';
  const entries = Object.entries(distObj);
  const total   = entries.reduce((s, [, v]) => s + Number(v), 0);
  if (total === 0) return '';
  return entries.map(([label, count]) => {
    const pct = Math.round((Number(count) / total) * 100);
    return `
      <div class="dist-row">
        <span class="dist-label">${label}</span>
        <div class="dist-bar-wrap">
          <div class="dist-bar ${colorClass}" style="width:${pct}%"></div>
        </div>
        <span class="dist-count">${count} <span class="dist-pct">(${pct}%)</span></span>
      </div>`;
  }).join('');
}

// ── 5. RENDU CHECK ───────────────────────────────────────────
function renderCheck(check) {
  if (!check || (typeof check === 'object' && Object.keys(check).length === 0)) {
    return '<div class="empty-state"><span class="empty-icon">o</span><p>Analyse de la situation actuelle.</p></div>';
  }
  let html = '';
  if (check.description) html += '<p class="check-desc">' + check.description + '</p>';

  const decouvertes = check.decouvertes || check.findings || [];
  if (Array.isArray(decouvertes) && decouvertes.length > 0) {
    html += decouvertes.map(function(d) {
      const nom  = d.nom || d.name || d.titre || '-';
      const comm = d.commentaire || d.comment || d.description || '-';
      const pos  = nom.toLowerCase().match(/fort|positif|strength|bon|bonne/);
      return '<div class="finding ' + (pos ? 'finding--pos' : 'finding--neg') + '">'
        + '<div class="finding-dot"></div>'
        + '<div><div class="finding-name">' + nom + '</div>'
        + '<div class="finding-comment">' + comm + '</div></div>'
        + '</div>';
    }).join('');
  } else if (check.analyse_check) {
    html += '<p class="check-desc">' + check.analyse_check + '</p>';
  }
  return html || '<div class="empty-state"><span class="empty-icon">o</span><p>Analyse de la situation actuelle.</p></div>';
}

// ── 6. RENDU ACT ─────────────────────────────────────────────
function renderAct(act) {
  if (!act || act.length === 0) {
    return '<div class="empty-state"><span class="empty-icon">o</span><p>Aucune decision enregistree pour ce cycle.</p></div>';
  }
  const rows = act.map(function(item) {
    const prio = (item.priorite || item.priority || '').toLowerCase();
    return '<tr>'
      + '<td>' + (item.action || item.Action || item.description || '-') + '</td>'
      + '<td><span class="prio prio--' + prio + '">' + (item.priorite || item.priority || '-') + '</span></td>'
      + '<td>' + (item.responsable || item.responsible || '-') + '</td>'
      + '<td>' + (item.delai || item.deadline || '-') + '</td>'
      + '<td>' + (item.cout_estime !== undefined ? fmtEur(item.cout_estime) : (item.cout || '-')) + '</td>'
      + '</tr>';
  }).join('');
  return '<div class="table-wrap"><table>'
    + '<thead><tr><th>Action</th><th>Priorite</th><th>Responsable</th><th>Delai</th><th>Cout estime</th></tr></thead>'
    + '<tbody>' + rows + '</tbody>'
    + '</table></div>';
}

// ── 7. RENDU PLAN ────────────────────────────────────────────
function renderPlan(plan) {
  if (!plan || (typeof plan === 'object' && Object.keys(plan).length === 0)) {
    return '<div class="empty-state"><span class="empty-icon">o</span><p>Aucun plan defini pour ce cycle.</p></div>';
  }
  if (plan.cycle_PDCA && typeof plan.cycle_PDCA === 'string') {
    try { plan = { cycle_PDCA: JSON.parse(plan.cycle_PDCA) }; } catch (_) {}
  }
  if (!plan.cycle_PDCA) {
    if (plan.objectif || plan.echeancier || plan.ressources_necessaires) {
      plan = { cycle_PDCA: plan };
    } else {
      return '<div class="empty-state"><span class="empty-icon">o</span><p>Structure du plan non reconnue.</p></div>';
    }
  }
  const c   = plan.cycle_PDCA;
  const obj = c.objectif || {};
  const res = c.ressources_necessaires || {};
  const ech = c.echeancier || {};
  const indicateurs = c.indicateurs_de_succes || obj.indicateur_de_succes || [];
  const outils      = res.outils || [];

  const timelineHtml = Object.entries(ech).map(function(entry) {
    const periode = entry[0], taches = entry[1];
    const chips = Array.isArray(taches)
      ? taches.map(function(t) { return '<span class="task-chip">' + String(t).trim() + '</span>'; }).join('')
      : '<span class="task-chip">' + taches + '</span>';
    return '<div class="timeline-row"><span class="tl-period">' + periode + '</span><div class="tl-tasks">' + chips + '</div></div>';
  }).join('');

  const indicateursHtml = Array.isArray(indicateurs)
    ? indicateurs.map(function(i) { return '<li>' + (typeof i === 'string' ? i.trim() : JSON.stringify(i)) + '</li>'; }).join('')
    : Object.keys(indicateurs).map(function(k) { return '<li>' + k + '</li>'; }).join('');

  const outilsHtml = outils.map(function(o) { return '<span class="tool-tag">' + String(o).trim() + '</span>'; }).join('');

  return '<div class="plan-objective">'
    + '<div class="plan-obj-title">' + (obj.titre || 'Objectif non defini') + '</div>'
    + '<div class="plan-obj-desc">' + (obj.description || '') + '</div>'
    + '</div>'
    + '<div class="plan-meta-grid">'
    + '<div class="plan-meta-card"><div class="meta-label">Budget alloue</div><div class="meta-value">' + (res.budget ? fmtEur(res.budget) : '-') + '</div></div>'
    + '<div class="plan-meta-card"><div class="meta-label">Personnel</div><div class="meta-value">' + safe(res.personnel) + '<span class="meta-unit"> pers.</span></div></div>'
    + '</div>'
    + (indicateursHtml ? '<div class="plan-block"><div class="plan-block-label">Indicateurs de succes</div><ul class="objectives-list">' + indicateursHtml + '</ul></div>' : '')
    + (outilsHtml ? '<div class="plan-block"><div class="plan-block-label">Outils requis</div><div class="tools-list">' + outilsHtml + '</div></div>' : '')
    + (timelineHtml ? '<div class="plan-block"><div class="plan-block-label">Echeancier</div><div class="timeline">' + timelineHtml + '</div></div>' : '');
}

// ── 8. HTML COMPLET ──────────────────────────────────────────
const html = '<!DOCTYPE html>\n<html lang="fr">\n<head>\n'
  + '<meta charset="UTF-8">\n'
  + '<meta name="viewport" content="width=device-width, initial-scale=1.0">\n'
  + '<title>Rapport PDCA - Qualite Industrielle</title>\n'
  + '<link rel="preconnect" href="https://fonts.googleapis.com">\n'
