  + '.timeline-row { display:flex; gap:12px; align-items:flex-start; }\n'
  + '.tl-period { font-size:10px; font-weight:700; padding:4px 10px; border-radius:12px; background:var(--blue-bg); color:var(--blue-text); border:1px solid #BDD0F2; white-space:nowrap; flex-shrink:0; margin-top:1px; }\n'
