  + '</style>\n</head>\n<body>\n<div class="page">\n'

  // Header
  + '<div class="header">'
  + '<div class="eyebrow">AI PDCA Orchestrator</div>'
  + '<h1>Rapport Qualite Industrielle</h1>'
  + '<div class="header-sub">' + today + '</div>'
