  + '<div class="section"><div class="section-header"><span class="phase-badge badge-act">Act</span><span class="section-title">Decisions et actions correctives</span></div>'
  + '<div class="section-body ' + (act.length > 0 ? 'no-pad' : '') + '">' + renderAct(act) + '</div></div>\n'

  // PLAN
  + '<div class="section"><div class="section-header"><span class="phase-badge badge-plan">Plan</span><span class="section-title">Plan d\'action - cycle PDCA</span></div>'
  + '<div class="section-body">' + renderPlan(plan) + '</div></div>\n'

  // DO
  + '<div class="section"><div class="section-header"><span class="phase-badge badge-do">Do</span><span class="section-title">Phase Do - simulation</span></div>'
  + '<div class="section-body"><div class="do-status">'
  + '<div class="do-icon"><svg width="13" height="13" viewBox="0 0 13 13" fill="none"><path d="M2 6.5L5 9.5L11 3.5" stroke="white" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg></div>'
  + '<div class="do-status-text">' + doMsg + '</div>'
  + '</div></div></div>\n'

  // Footer
  + '<div class="footer">Genere automatiquement &middot; <strong>' + today + '</strong> &middot; AI PDCA Orchestrator</div>\n'
  + '</div>\n</body>\n</html>';

return [{
  json: {},
  binary: {
    data: {
      fileName: 'PDCA_Rapport_Qualite_' + new Date().toISOString().slice(0, 10) + '.html',
      mimeType: 'text/html',
      data: Buffer.from(html).toString('base64')
    }
